import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新日志: 版本历史 | Plannotator","description":"了解 Plannotator 版本历史和新功能。查看主要更新、bug 修复和性能改进，掌握代码评审、图像标注、Obsidian 集成等新特性。","frontmatter":{"title":"更新日志: 版本历史 | Plannotator","sidebarTitle":"看看新功能","subtitle":"更新日志: 版本历史 | Plannotator","description":"了解 Plannotator 版本历史和新功能。查看主要更新、bug 修复和性能改进，掌握代码评审、图像标注、Obsidian 集成等新特性。","tags":["更新日志","版本历史","新功能","bug 修复"],"order":1},"headers":[],"relativePath":"zh/backnotprop/plannotator/changelog/release-notes/index.md","filePath":"zh/backnotprop/plannotator/changelog/release-notes/index.md"}'),n={name:"zh/backnotprop/plannotator/changelog/release-notes/index.md"};function l(i,t,s,p,g,c){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="更新日志-plannotator-版本历史和新功能" tabindex="-1">更新日志：Plannotator 版本历史和新功能 <a class="header-anchor" href="#更新日志-plannotator-版本历史和新功能" aria-label="Permalink to &quot;更新日志：Plannotator 版本历史和新功能&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>✅ 了解 Plannotator 的版本历史和新功能</li><li>✅ 掌握每个版本的主要更新和改进</li><li>✅ 了解 bug 修复和性能优化</li></ul><hr><h2 id="最新版本" tabindex="-1">最新版本 <a class="header-anchor" href="#最新版本" aria-label="Permalink to &quot;最新版本&quot;">​</a></h2><h3 id="v0-6-7-2026-01-24" tabindex="-1">v0.6.7 (2026-01-24) <a class="header-anchor" href="#v0-6-7-2026-01-24" aria-label="Permalink to &quot;v0.6.7 (2026-01-24)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>Comment mode</strong>：添加 Comment 模式，支持在计划中直接输入评论</li><li><strong>Type-to-comment shortcut</strong>：添加快捷键支持，直接输入评论内容</li></ul><p><strong>改进</strong>：</p><ul><li>修复 OpenCode 插件的 sub-agent blocking 问题</li><li>修复 prompt injection 安全漏洞（CVE）</li><li>改进 OpenCode 中的 agent switching 智能检测</li></ul><p><strong>源码参考</strong>：</p><ul><li>Comment mode: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L23-L42" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></li><li>Type-to-comment: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L80-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></li></ul><hr><h3 id="v0-6-6-2026-01-20" tabindex="-1">v0.6.6 (2026-01-20) <a class="header-anchor" href="#v0-6-6-2026-01-20" aria-label="Permalink to &quot;v0.6.6 (2026-01-20)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>修复 OpenCode plugin 的 CVE 安全漏洞</li><li>修复 sub-agent blocking 问题，防止 prompt injection</li><li>改进 agent switching 的智能检测逻辑</li></ul><p><strong>源码参考</strong>：</p><ul><li>OpenCode plugin: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L245-L280" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li><li>Agent switching: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/agentSwitch.ts#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/utils/agentSwitch.ts</code></a></li></ul><hr><h3 id="v0-6-5-2026-01-15" tabindex="-1">v0.6.5 (2026-01-15) <a class="header-anchor" href="#v0-6-5-2026-01-15" aria-label="Permalink to &quot;v0.6.5 (2026-01-15)&quot;">​</a></h3><p><strong>改进</strong>：</p><ul><li><strong>Hook timeout 增加</strong>：将 hook timeout 从默认值增加到 4 天，适应长时间运行的 AI 计划</li><li><strong>修复 copy 功能</strong>：保留 copy 操作中的 newlines</li><li><strong>新增 Cmd+C 快捷键</strong>：添加 Cmd+C 快捷键支持</li></ul><p><strong>源码参考</strong>：</p><ul><li>Hook timeout: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L44-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></li><li>Copy newlines: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L150-L170" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></li></ul><hr><h3 id="v0-6-4-2026-01-10" tabindex="-1">v0.6.4 (2026-01-10) <a class="header-anchor" href="#v0-6-4-2026-01-10" aria-label="Permalink to &quot;v0.6.4 (2026-01-10)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>Cmd+Enter 快捷键</strong>：支持使用 Cmd+Enter（Windows: Ctrl+Enter）提交审批或反馈</li></ul><p><strong>改进</strong>：</p><ul><li>优化键盘操作体验</li></ul><p><strong>源码参考</strong>：</p><ul><li>Keyboard shortcuts: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L323" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a> (Cmd+Enter 快捷键功能在各组件中直接实现)</li></ul><hr><h3 id="v0-6-3-2026-01-05" tabindex="-1">v0.6.3 (2026-01-05) <a class="header-anchor" href="#v0-6-3-2026-01-05" aria-label="Permalink to &quot;v0.6.3 (2026-01-05)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>修复 skip-title-generation-prompt 问题</li></ul><p><strong>源码参考</strong>：</p><ul><li>Skip title: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L67-L71" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li></ul><hr><h3 id="v0-6-2-2026-01-01" tabindex="-1">v0.6.2 (2026-01-01) <a class="header-anchor" href="#v0-6-2-2026-01-01" aria-label="Permalink to &quot;v0.6.2 (2026-01-01)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>修复 OpenCode 插件中 HTML 文件未包含在 npm 包中的问题</li></ul><p><strong>源码参考</strong>：</p><ul><li>OpenCode plugin build: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li></ul><hr><h3 id="v0-6-1-2025-12-20" tabindex="-1">v0.6.1 (2025-12-20) <a class="header-anchor" href="#v0-6-1-2025-12-20" aria-label="Permalink to &quot;v0.6.1 (2025-12-20)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>Bear 集成</strong>：支持将批准的计划自动保存到 Bear 笔记应用</li></ul><p><strong>改进</strong>：</p><ul><li>改进 Obsidian 集成的标签生成逻辑</li><li>优化 Obsidian vault 检测机制</li></ul><p><strong>源码参考</strong>：</p><ul><li>Bear 集成: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L280" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Obsidian 集成: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L136-L220" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li></ul><hr><h2 id="重大功能发布" tabindex="-1">重大功能发布 <a class="header-anchor" href="#重大功能发布" aria-label="Permalink to &quot;重大功能发布&quot;">​</a></h2><h3 id="code-review-功能-2026-01" tabindex="-1">Code Review 功能 (2026-01) <a class="header-anchor" href="#code-review-功能-2026-01" aria-label="Permalink to &quot;Code Review 功能 (2026-01)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>代码评审工具</strong>：运行 <code>/plannotator-review</code> 命令，可视化评审 Git diff</li><li><strong>行级注释</strong>：点击行号选择代码范围，添加 comment/suggestion/concern 类型的注释</li><li><strong>多种 diff 视图</strong>：支持切换 uncommitted/staged/last-commit/branch 等不同的 diff 类型</li><li><strong>Agent 集成</strong>：发送结构化反馈给 AI agent，支持自动响应</li></ul><p><strong>使用方法</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在项目目录中运行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>相关教程</strong>：</p><ul><li><a href="./../../platforms/code-review-basics/">代码评审基础</a></li><li><a href="./../../platforms/code-review-annotations/">添加代码注释</a></li><li><a href="./../../platforms/code-review-diff-types/">切换 Diff 视图</a></li></ul><p><strong>源码参考</strong>：</p><ul><li>Code review server: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></li><li>Code review UI: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></li><li>Git diff 工具: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></li></ul><hr><h3 id="图像标注功能-2026-01" tabindex="-1">图像标注功能 (2026-01) <a class="header-anchor" href="#图像标注功能-2026-01" aria-label="Permalink to &quot;图像标注功能 (2026-01)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>上传图片</strong>：在计划和代码评审中上传图片附件</li><li><strong>标注工具</strong>：提供画笔、箭头、圆形三种标注工具</li><li><strong>可视化标注</strong>：在图片上直接标注，增强评审反馈效果</li></ul><p><strong>相关教程</strong>：</p><ul><li><a href="./../../platforms/plan-review-images/">添加图像标注</a></li></ul><p><strong>源码参考</strong>：</p><ul><li>Image annotator: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/ImageAnnotator/index.tsx" target="_blank" rel="noreferrer"><code>packages/ui/components/ImageAnnotator/index.tsx</code></a></li><li>Upload API: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L160-L180" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></li></ul><hr><h3 id="obsidian-集成-2025-12" tabindex="-1">Obsidian 集成 (2025-12) <a class="header-anchor" href="#obsidian-集成-2025-12" aria-label="Permalink to &quot;Obsidian 集成 (2025-12)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>自动检测 vaults</strong>：自动检测 Obsidian vault 配置文件路径</li><li><strong>自动保存计划</strong>：批准的计划自动保存到 Obsidian</li><li><strong>生成 frontmatter</strong>：自动包含 created、source、tags 等 frontmatter</li><li><strong>智能标签提取</strong>：从计划内容中提取关键词作为标签</li></ul><p><strong>配置方式</strong>： 无需额外配置，Plannotator 会自动检测 Obsidian 安装路径。</p><p><strong>相关教程</strong>：</p><ul><li><a href="./../../advanced/obsidian-integration/">Obsidian 集成</a></li></ul><p><strong>源码参考</strong>：</p><ul><li>Obsidian 检测: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L136-L145" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Obsidian 保存: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L220" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Frontmatter 生成: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L50-L80" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></li></ul><hr><h3 id="url-分享功能-2025-11" tabindex="-1">URL 分享功能 (2025-11) <a class="header-anchor" href="#url-分享功能-2025-11" aria-label="Permalink to &quot;URL 分享功能 (2025-11)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>无后端分享</strong>：将计划和注释压缩到 URL hash 中，无需后端服务器</li><li><strong>一键分享</strong>：点击 Export → Share as URL，生成分享链接</li><li><strong>只读模式</strong>：协作者打开 URL 后查看但无法提交决策</li></ul><p><strong>技术实现</strong>：</p><ul><li>使用 Deflate 压缩算法</li><li>Base64 编码 + URL 安全字符替换</li><li>支持最大 payload 约 7 个标签</li></ul><p><strong>相关教程</strong>：</p><ul><li><a href="./../../advanced/url-sharing/">URL 分享</a></li></ul><p><strong>源码参考</strong>：</p><ul><li>Sharing utils: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/sharing.ts" target="_blank" rel="noreferrer"><code>packages/ui/utils/sharing.ts</code></a></li><li>Share hook: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/hooks/useSharing.ts" target="_blank" rel="noreferrer"><code>packages/ui/hooks/useSharing.ts</code></a></li></ul><hr><h3 id="远程-devcontainer-模式-2025-10" tabindex="-1">远程/Devcontainer 模式 (2025-10) <a class="header-anchor" href="#远程-devcontainer-模式-2025-10" aria-label="Permalink to &quot;远程/Devcontainer 模式 (2025-10)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>远程模式支持</strong>：在 SSH、devcontainer、WSL 等远程环境中使用 Plannotator</li><li><strong>固定端口</strong>：通过环境变量设置固定端口</li><li><strong>端口转发</strong>：自动输出 URL 供用户手动打开浏览器</li><li><strong>浏览器控制</strong>：通过 <code>PLANNOTATOR_BROWSER</code> 环境变量控制是否打开浏览器</li></ul><p><strong>环境变量</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE=1</code>：启用远程模式</li><li><code>PLANNOTATOR_PORT=3000</code>：设置固定端口</li><li><code>PLANNOTATOR_BROWSER=disabled</code>：禁用自动打开浏览器</li></ul><p><strong>相关教程</strong>：</p><ul><li><a href="./../../advanced/remote-mode/">远程/Devcontainer 模式</a></li><li><a href="./../../advanced/environment-variables/">环境变量配置</a></li></ul><p><strong>源码参考</strong>：</p><ul><li>Remote mode: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/remote.ts" target="_blank" rel="noreferrer"><code>packages/server/remote.ts</code></a></li><li>Browser control: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/browser.ts" target="_blank" rel="noreferrer"><code>packages/server/browser.ts</code></a></li></ul><hr><h2 id="版本兼容性" tabindex="-1">版本兼容性 <a class="header-anchor" href="#版本兼容性" aria-label="Permalink to &quot;版本兼容性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plannotator 版本</th><th>Claude Code</th><th>OpenCode</th><th>Bun 最低版本</th></tr></thead><tbody><tr><td>v0.6.x</td><td>2.1.7+</td><td>1.0+</td><td>1.0+</td></tr><tr><td>v0.5.x</td><td>2.1.0+</td><td>0.9+</td><td>0.7+</td></tr></tbody></table><p><strong>升级建议</strong>：</p><ul><li>保持 Plannotator 为最新版本，以获得最新功能和安全修复</li><li>Claude Code 和 OpenCode 也应保持最新版本</li></ul><hr><h2 id="许可证变更" tabindex="-1">许可证变更 <a class="header-anchor" href="#许可证变更" aria-label="Permalink to &quot;许可证变更&quot;">​</a></h2><p><strong>当前版本（v0.6.7+）</strong>：Business Source License 1.1 (BSL-1.1)</p><p><strong>许可证详情</strong>：</p><ul><li>允许：个人使用、内部商业使用</li><li>限制：提供托管服务、SaaS 产品</li><li>详情见 <a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a></li></ul><hr><h2 id="反馈与支持" tabindex="-1">反馈与支持 <a class="header-anchor" href="#反馈与支持" aria-label="Permalink to &quot;反馈与支持&quot;">​</a></h2><p><strong>报告问题</strong>：</p><ul><li>GitHub Issues: <a href="https://github.com/backnotprop/plannotator/issues" target="_blank" rel="noreferrer">https://github.com/backnotprop/plannotator/issues</a></li></ul><p><strong>功能建议</strong>：</p><ul><li>在 GitHub Issues 中提交 feature request</li></ul><p><strong>安全漏洞</strong>：</p><ul><li>请通过私密渠道报告安全漏洞</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>你已经了解了 Plannotator 的版本历史和新功能。</p><p>接下来可以：</p><ul><li>返回 <a href="./../../start/getting-started/">快速开始</a> 学习如何安装和使用</li><li>查看 <a href="./../../faq/common-problems/">常见问题</a> 解决使用中的问题</li><li>阅读 <a href="./../../appendix/api-reference/">API 参考</a> 了解所有 API 端点</li></ul></blockquote>`,121)])])}const u=a(n,[["render",l]]);export{h as __pageData,u as default};
